 CREATE TABLE calls (id uuid NOT NULL, client_id uuid NOT NULL, user_id uuid NOT NULL, phone_number text NOT NULL, dial_time timestamp with time zone, duration integer(32,0), notes text, reason text, status text, created_at timestamp with time zone, updated_at timestamp with time zone);
 CREATE TABLE clients (id uuid NOT NULL, first_name text NOT NULL, last_name text NOT NULL, middle_name text, client_type text, created_at timestamp with time zone, updated_at timestamp with time zone);
